// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with the order object injected as a global variable, and returns the resulting discount amount.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// Inject the entire order map as a single global variable named 'order'
	// This ensures the script can access fields like order.total
	if err := vm.Set("order", order); err != nil {
		return 0.0, fmt.Errorf("failed to set variable 'order': %w", err)
	}

	// Prepare for execution with timeout to prevent infinite loops
	type execResult struct {
		value goja.Value
		err   error
	}
	resCh := make(chan execResult, 1)

	go func() {
		val, err := vm.RunString(script)
		resCh <- execResult{value: val, err: err}
	}()

	// Set a timeout to prevent DoS attacks via infinite loops
	const timeout = 2 * time.Second

	select {
	case res := <-resCh:
		if res.err != nil {
			return 0.0, fmt.Errorf("script execution error: %w", res.err)
		}

		// Check if the result is a number type in JavaScript
		if !goja.IsNumber(res.value) {
			return 0.0, fmt.Errorf("script must return a number, got %s", res.value.ExportType().String())
		}

		// Convert result to float64
		discount := res.value.ToFloat()

		// Check for NaN (Not a Number)
		if math.IsNaN(discount) {
			return 0.0, fmt.Errorf("script resulted in NaN (Not a Number)")
		}

		return discount, nil

	case <-time.After(timeout):
		// Interrupt the VM execution to stop the infinite loop
		vm.Interrupt("execution timeout")
		<-resCh // Wait for the goroutine to finish after interruption
		return 0.0, fmt.Errorf("script execution timed out")
	}
}

func main() {
	// Example usage
	// The script now accesses the 'order' object
	script := `if (order.total > 100) { return order.total * 0.1; } else { return 0; }`
	order := map[string]interface{}{
		"total":         150.0,
		"customerLevel": "gold",
	}

	discount, err := CalculateDiscount(script, order)
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Printf("Calculated Discount: %.2f\n", discount)
	}
}

