package main

import (
	"fmt"
	"time"

	"github.com/dop251/goja"
)

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM.
// It injects the order object securely, enforces a timeout to prevent infinite loops,
// and returns the resulting discount amount.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	// Security: Define a timeout to prevent resource exhaustion (e.g., infinite loops)
	const timeout = 100 * time.Millisecond

	vm := goja.New()

	// Security: Disable console to prevent unwanted side effects or information leakage
	vm.Set("console", nil)

	// Security: Inject the order as a single object 'order' rather than individual global variables.
	// This prevents global namespace pollution where an order field (e.g., "Math") might overwrite
	// built-in JavaScript objects, leading to unexpected behavior or security bypasses.
	vm.Set("order", order)

	// Channel to capture the result from the execution goroutine
	type vmResult struct {
		value goja.Value
		err   error
	}
	resultCh := make(chan vmResult, 1)

	// Run the script in a separate goroutine to allow for timeout enforcement
	go func() {
		val, err := vm.RunString(script)
		resultCh <- vmResult{value: val, err: err}
	}()

	// Wait for the script to finish or for the timeout to expire
	select {
	case res := <-resultCh:
		if res.err != nil {
			return 0.0, fmt.Errorf("script execution error: %w", res.err)
		}
		return extractFloat64(res.value)
	case <-time.After(timeout):
		// Security: Interrupt the VM if the script runs too long
		vm.Interrupt("execution timeout")
		return 0.0, fmt.Errorf("script execution timed out after %v", timeout)
	}
}

// extractFloat64 converts the Goja value to a float64, handling various numeric types.
func extractFloat64(result goja.Value) (float64, error) {
	if result == nil {
		return 0.0, fmt.Errorf("script returned nil")
	}

	exported := result.Export()
	discount, ok := exported.(float64)
	if !ok {
		// Try to convert from other numeric types (e.g., int, float32)
		switch v := exported.(type) {
		case int:
			discount = float64(v)
		case int32:
			discount = float64(v)
		case int64:
			discount = float64(v)
		case float32:
			discount = float64(v)
		default:
			return 0.0, fmt.Errorf("script must return a number, got %T", exported)
		}
	}

	return discount, nil
}

