package main

import (
	"errors"
	"fmt"

	"github.com/dop251/goja"
)

// CalculateDiscount executes a JavaScript script to calculate a discount based on the order.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	// Create a new Goja runtime
	vm := goja.New()

	// Set the order map as a global variable named "order" in the JS environment.
	// goja automatically converts map[string]interface{} to a JavaScript Object,
	// allowing access to keys like order.total, order.memberLevel, etc.
	if err := vm.Set("order", order); err != nil {
		return 0, fmt.Errorf("failed to set order variable: %w", err)
	}

	// Execute the provided script
	val, err := vm.RunString(script)
	if err != nil {
		return 0, fmt.Errorf("script execution failed: %w", err)
	}

	// Validate that the return value is a number
	if !goja.IsNumber(val) {
		return 0, errors.New("script did not return a number")
	}

	// Convert the JavaScript number to Go float64
	return val.ToFloat(), nil
}

func main() {
	// Example order data
	order := map[string]interface{}{
		"total":       200.00,
		"memberLevel": "gold",
		"items":       3,
	}

	// Example JavaScript rule:
	// If member is gold and total > 100, give 15% discount.
	// Otherwise, give 5% discount.
	script := `
		if (order.memberLevel === 'gold' && order.total > 100) {
			return order.total * 0.15;
		} else {
			return order.total * 0.05;
		}
	`

	discount, err := CalculateDiscount(script, order)
	if err != nil {
		fmt.Printf("Error calculating discount: %v\n", err)
		return
	}

	fmt.Printf("Order Total: %.2f\n", order["total"])
	fmt.Printf("Calculated Discount: %.2f\n", discount)
}

